import{_ as t,c as o,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"ToS警告: アカウントリスクと安全な運用方法 | Antigravity Auth","description":"Antigravity Authプラグインの使用リスクとアカウントセキュリティのベストプラクティスを学びましょう。高リスクシナリオ、シャドウバン仕組み、レート制限との違いを理解し、複数アカウント戦略、使用量コントロール、アカウントウォームアップ方法を習得します。","frontmatter":{"title":"ToS警告: アカウントリスクと安全な運用方法 | Antigravity Auth","sidebarTitle":"アカウント停止を防ぐ","subtitle":"ToS警告: アカウントリスクと安全な運用方法","description":"Antigravity Authプラグインの使用リスクとアカウントセキュリティのベストプラクティスを学びましょう。高リスクシナリオ、シャドウバン仕組み、レート制限との違いを理解し、複数アカウント戦略、使用量コントロール、アカウントウォームアップ方法を習得します。","tags":["FAQ","リスク警告","アカウントセキュリティ"],"prerequisite":["start-quick-install"],"order":5},"headers":[],"relativePath":"ja/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md","filePath":"ja/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"}'),e={name:"ja/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"};function r(n,l,s,d,h,g){return a(),o("div",null,[...l[0]||(l[0]=[i('<h1 id="tos警告" tabindex="-1">ToS警告 <a class="header-anchor" href="#tos警告" aria-label="Permalink to &quot;ToS警告&quot;">​</a></h1><p>このレッスンを完了すると、Antigravity Authプラグインを使用することで直面する可能性のあるリスクと、Googleアカウントの安全を保つ方法について理解できるようになります。</p><h2 id="あなたが直面している状況" tabindex="-1">あなたが直面している状況 <a class="header-anchor" href="#あなたが直面している状況" aria-label="Permalink to &quot;あなたが直面している状況&quot;">​</a></h2><p>Antigravity Authプラグインを使用してGoogle AntigravityのAIモデルにアクセスすることを検討していますが、いくつかの懸念があります：</p><ul><li>コミュニティでアカウントの停止やシャドウバンを報告している人を見かける</li><li>非公式ツールの使用がGoogleの利用規約に違反するのではないかと心配</li><li>新しいアカウントを使うべきか、既存のアカウントを使うべきかわからない</li><li>リスクを軽減する方法を知りたい</li></ul><p>これらの懸念は妥当です。非公式ツールを使用することには一定のリスクが伴います。この記事では、具体的なリスクポイントと対策について説明します。</p><h2 id="このレッスンを見るべきタイミング" tabindex="-1">このレッスンを見るべきタイミング <a class="header-anchor" href="#このレッスンを見るべきタイミング" aria-label="Permalink to &quot;このレッスンを見るべきタイミング&quot;">​</a></h2><ul><li><strong>プラグインをインストールする前</strong>：使用するかどうかを決める前にリスクを理解する</li><li><strong>アカウントを選択するとき</strong>：どのGoogleアカウントで認証するかを決める</li><li><strong>停止に遭遇したとき</strong>：考えられる原因と予防策を理解する</li><li><strong>新規ユーザー登録時</strong>：高リスクな操作パターンを避ける</li></ul><hr><h2 id="コアリスクの概要" tabindex="-1">コアリスクの概要 <a class="header-anchor" href="#コアリスクの概要" aria-label="Permalink to &quot;コアリスクの概要&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">重要な警告</p><p><strong>このプラグインを使用することは、Googleの利用規約（Terms of Service）に違反する可能性があります。</strong></p><p>一部のユーザーから、Googleアカウントが停止されたりシャドウバン（Shadow Ban、明確な通知なく制限を受ける状態）されたりしたという報告を受けています。</p><p><strong>このプラグインを使用することで、以下の事項に同意したものとみなされます：</strong></p><ol><li>これは非公式ツールであり、Googleの承認や推奨を受けていない</li><li>Googleアカウントが一時停止または永久停止される可能性がある</li><li>このプラグインを使用することによるすべてのリスクと結果は自己責任となる</li></ol></div><h3 id="シャドウバンとは" tabindex="-1">シャドウバンとは？ <a class="header-anchor" href="#シャドウバンとは" aria-label="Permalink to &quot;シャドウバンとは？&quot;">​</a></h3><p>**シャドウバン（Shadow Ban）**は、Googleが疑わしいアカウントに対して講じる制限措置です。通常の停止とは異なり、シャドウバンでは明確なエラーメッセージは表示されませんが：</p><ul><li>APIリクエストが403または429エラーを返す</li><li>クォータは表示されているが、実際には呼び出せない</li><li>他のアカウントは正常に動作しているが、マークされたアカウントのみ影響を受ける</li></ul><p>シャドウバンの期間は通常長く（数日から数週間）、異議申し立てによって回復することはできません。</p><hr><h2 id="高リスクシナリオ" tabindex="-1">高リスクシナリオ <a class="header-anchor" href="#高リスクシナリオ" aria-label="Permalink to &quot;高リスクシナリオ&quot;">​</a></h2><p>以下のシナリオは、アカウントがマークされたり停止されたりするリスクを大幅に高めます：</p><h3 id="🚨-シナリオ1-新しいgoogleアカウント" tabindex="-1">🚨 シナリオ1：新しいGoogleアカウント <a class="header-anchor" href="#🚨-シナリオ1-新しいgoogleアカウント" aria-label="Permalink to &quot;🚨 シナリオ1：新しいGoogleアカウント&quot;">​</a></h3><p><strong>リスクレベル：極めて高い</strong></p><p>新規登録したGoogleアカウントでこのプラグインを使用すると、停止される確率が非常に高くなります。理由：</p><ul><li>新しいアカウントは履歴行動データがないため、Googleの悪用検出システムにマークされやすい</li><li>新しいアカウントでの大量のAPI呼び出しは異常な行動と見なされる</li><li>Googleは新しいアカウントの審査をより厳しく行う</li></ul><p><strong>推奨</strong>：このプラグインのために新しいアカウントを作成しないでください。</p><h3 id="🚨-シナリオ2-新しいアカウント-pro-ultraサブスクリプション" tabindex="-1">🚨 シナリオ2：新しいアカウント＋Pro/Ultraサブスクリプション <a class="header-anchor" href="#🚨-シナリオ2-新しいアカウント-pro-ultraサブスクリプション" aria-label="Permalink to &quot;🚨 シナリオ2：新しいアカウント＋Pro/Ultraサブスクリプション&quot;">​</a></h3><p><strong>リスクレベル：極めて高い</strong></p><p>新規登録したアカウントでGoogleのProまたはUltraサービスに即座にサブスクライブすると、頻繁にマークされて停止されます。理由：</p><ul><li>新しいアカウントでのサブスクリプション後の高用量パターンは悪用に見える</li><li>Googleは新しい有料ユーザーの審査をより厳しく行う</li><li>このパターンは通常ユーザーの成長パスとは大きく異なる</li></ul><p><strong>推奨</strong>：サブスクリプションを検討する前に、アカウントを「自然に成長」させる時間（少なくとも数ヶ月）を与えてください。</p><h3 id="🟡-シナリオ3-短時間での大量リクエスト" tabindex="-1">🟡 シナリオ3：短時間での大量リクエスト <a class="header-anchor" href="#🟡-シナリオ3-短時間での大量リクエスト" aria-label="Permalink to &quot;🟡 シナリオ3：短時間での大量リクエスト&quot;">​</a></h3><p><strong>リスクレベル：高い</strong></p><p>短時間に大量のAPIリクエストを行ったり、並行プロキシ/複数セッションを頻繁に使用したりすると、レート制限と悪用検出がトリガーされます。理由：</p><ul><li>OpenCodeのリクエストパターンはネイティブアプリよりも密（ツール呼び出し、リトライ、ストリーミングなど）</li><li>高並行リクエストはGoogleの保護メカニズムをトリガーする</li></ul><p><strong>推奨</strong>：</p><ul><li>リクエスト頻度と並行数をコントロールする</li><li>同時に複数の並行プロキシを起動しない</li><li>複数アカウントでリクエストを分散する</li></ul><h3 id="🟡-シナリオ4-唯一のgoogleアカウントを使用" tabindex="-1">🟡 シナリオ4：唯一のGoogleアカウントを使用 <a class="header-anchor" href="#🟡-シナリオ4-唯一のgoogleアカウントを使用" aria-label="Permalink to &quot;🟡 シナリオ4：唯一のGoogleアカウントを使用&quot;">​</a></h3><p><strong>リスクレベル：中程度</strong></p><p>唯一のGoogleアカウントを持っており、Gmail、Driveなどの重要なサービスに依存している場合、リスクはより高くなります。理由：</p><ul><li>アカウントが停止されると、日々の作業に影響を与える</li><li>異議申し立てによって回復できない</li><li>代替案がない</li></ul><p><strong>推奨</strong>：重要なサービスに依存しない独立したアカウントを使用してください。</p><hr><h2 id="ベストプラクティス推奨" tabindex="-1">ベストプラクティス推奨 <a class="header-anchor" href="#ベストプラクティス推奨" aria-label="Permalink to &quot;ベストプラクティス推奨&quot;">​</a></h2><h3 id="✅-推奨される方法" tabindex="-1">✅ 推奨される方法 <a class="header-anchor" href="#✅-推奨される方法" aria-label="Permalink to &quot;✅ 推奨される方法&quot;">​</a></h3><p><strong>1. 既存のGoogleアカウントを使用する</strong></p><p>しばらく使用している（6ヶ月以上推奨）Googleアカウントを優先的に選択してください：</p><ul><li>Gmail、Drive、Google SearchなどのGoogleサービスで通常の使用履歴がある</li><li>過去に違反履歴がない</li><li>電話番号が紐付けられ、検証が完了している</li></ul><p><strong>2. 複数アカウントを設定する</strong></p><p>複数のGoogleアカウントを追加し、ローテーションでリクエストを分散させます：</p><ul><li>少なくとも2-3つのアカウントを設定する</li><li><code>account_selection_strategy: &quot;hybrid&quot;</code> 戦略（デフォルト）を使用する</li><li>レート制限に遭遇した際に自動的にアカウントを切り替える</li></ul><p><strong>3. 使用量をコントロールする</strong></p><ul><li>短時間に集中したリクエストを避ける</li><li>並行プロキシの数を減らす</li><li><code>antigravity.json</code> で <code>max_rate_limit_wait_seconds: 0</code> を設定し、リトライせずに素早く失敗する</li></ul><p><strong>4. アカウント状態をモニタリングする</strong></p><p>定期的にアカウント状態を確認してください：</p><ul><li><code>~/.config/opencode/antigravity-accounts.json</code> の <code>rateLimitResetTimes</code> を確認する</li><li>デバッグログを有効にする：<code>OPENCODE_ANTIGRAVITY_DEBUG=1 opencode</code></li><li>403/429エラーが発生した場合は、24-48時間の使用を停止する</li></ul><p><strong>5. まず公式インターフェースで「ウォームアップ」する</strong></p><p>コミュニティユーザーが報告した効果的な方法：</p><ol><li>ブラウザで <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a> にログインする</li><li>いくつかの簡単なプロンプトを実行する（例：「こんにちは」、「2+2はいくつ？」）</li><li>5-10回の成功した呼び出し後、プラグインを使用する</li></ol><p><strong>原理</strong>：公式インターフェースからアカウントを使用すると、Googleがこれを通常のユーザーの行動と認識し、マークされるリスクが低下します。</p><h3 id="❌-避けるべき方法" tabindex="-1">❌ 避けるべき方法 <a class="header-anchor" href="#❌-避けるべき方法" aria-label="Permalink to &quot;❌ 避けるべき方法&quot;">​</a></h3><ul><li>❌ このプラグインのために新しいGoogleアカウントを作成する</li><li>❌ 新規登録したアカウントで即座にPro/Ultraにサブスクライブする</li><li>❌ 唯一の重要なサービスアカウント（例：仕事用メール）を使用する</li><li>❌ 429制限がトリガーされた後、繰り返しリトライする</li><li>❌ 同時に大量の並行プロキシを起動する</li><li>❌ <code>antigravity-accounts.json</code> をバージョン管理にコミットする</li></ul><hr><h2 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h2><h3 id="q-アカウントが停止されました。異議申し立てはできますか" tabindex="-1">Q: アカウントが停止されました。異議申し立てはできますか？ <a class="header-anchor" href="#q-アカウントが停止されました。異議申し立てはできますか" aria-label="Permalink to &quot;Q: アカウントが停止されました。異議申し立てはできますか？&quot;">​</a></h3><p><strong>A: できません。</strong></p><p>このプラグインを使用してGoogleの悪用検出をトリガーしたことによる停止やシャドウバンは、通常、異議申し立てによって回復することはできません。理由：</p><ul><li>停止はAPI使用パターンに基づいて自動的にトリガーされる</li><li>Googleは非公式ツールの使用を厳しく見ている</li><li>異議申し立てを行う際にツールの用途を説明する必要があるが、このプラグイン自体が違反と見なされる可能性がある</li></ul><p><strong>推奨</strong>：</p><ul><li>影響を受けていない他のアカウントを使用する</li><li>すべてのアカウントが停止された場合、<a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a> を直接使用する</li><li>停止されたアカウントで試行を続けるのを避ける</li></ul><h3 id="q-このプラグインを使用すると必ず停止されますか" tabindex="-1">Q: このプラグインを使用すると必ず停止されますか？ <a class="header-anchor" href="#q-このプラグインを使用すると必ず停止されますか" aria-label="Permalink to &quot;Q: このプラグインを使用すると必ず停止されますか？&quot;">​</a></h3><p><strong>A: 必ずしもそうではありません。</strong></p><p>ほとんどのユーザーは、このプラグインを使用して問題に遭遇していません。リスクは以下の要因によって異なります：</p><ul><li>アカウントの経過時間と履歴行動</li><li>使用頻度とリクエストパターン</li><li>ベストプラクティスに従っているかどうか</li></ul><p><strong>リスク評価</strong>：</p><ul><li>古いアカウント＋適度な使用＋複数アカウントローテーション → 低リスク</li><li>新しいアカウント＋密集したリクエスト＋単一アカウント → 高リスク</li></ul><h3 id="q-シャドウバンとレート制限の違いは何ですか" tabindex="-1">Q: シャドウバンとレート制限の違いは何ですか？ <a class="header-anchor" href="#q-シャドウバンとレート制限の違いは何ですか" aria-label="Permalink to &quot;Q: シャドウバンとレート制限の違いは何ですか？&quot;">​</a></h3><p><strong>A: 本質的に異なり、回復方法も異なります。</strong></p><table tabindex="0"><thead><tr><th>特徴</th><th>シャドウバン</th><th>レート制限（429）</th></tr></thead><tbody><tr><td>トリガー原因</td><td>悪用検出、疑わしいとマークされる</td><td>クォータを超えるリクエスト頻度</td></tr><tr><td>エラーコード</td><td>403または静かな失敗</td><td>429 Too Many Requests</td></tr><tr><td>期間</td><td>数日から数週間</td><td>数時間から1日</td></tr><tr><td>回復方法</td><td>回復不可、他のアカウントが必要</td><td>リセットを待つかアカウントを切り替える</td></tr><tr><td>予防可能か</td><td>ベストプラクティスに従うことでリスク軽減</td><td>リクエスト頻度をコントロールする</td></tr></tbody></table><h3 id="q-google-for-businessアカウントを使用できますか" tabindex="-1">Q: Google for Businessアカウントを使用できますか？ <a class="header-anchor" href="#q-google-for-businessアカウントを使用できますか" aria-label="Permalink to &quot;Q: Google for Businessアカウントを使用できますか？&quot;">​</a></h3><p><strong>A: 推奨しません。</strong></p><p>ビジネスアカウントは通常、重要なサービスとデータにバインドされており、停止による影響はより深刻です。また：</p><ul><li>ビジネスアカウントの審査はより厳しい</li><li>企業のITポリシーに違反する可能性がある</li><li>リスクは個人が負うが、影響はチーム全体に及ぶ</li></ul><p><strong>推奨</strong>：個人アカウントを使用してください。</p><h3 id="q-複数アカウントで完全に停止を回避できますか" tabindex="-1">Q: 複数アカウントで完全に停止を回避できますか？ <a class="header-anchor" href="#q-複数アカウントで完全に停止を回避できますか" aria-label="Permalink to &quot;Q: 複数アカウントで完全に停止を回避できますか？&quot;">​</a></h3><p><strong>A: 完全には回避できませんが、影響を軽減できます。</strong></p><p>複数アカウントの効果：</p><ul><li>リクエストを分散させ、単一アカウントが制限をトリガーする確率を低下させる</li><li>1つのアカウントが停止されても、他のアカウントは引き続き使用可能</li><li>制限に遭遇した場合、自動的にアカウントを切り替えて可用性を向上させる</li></ul><p><strong>しかし、複数アカウントは「お守り」ではありません</strong>：</p><ul><li>すべてのアカウントが悪用検出をトリガーした場合、すべて停止される可能性がある</li><li>複数アカウントを悪用して密集したリクエストを行わない</li><li>各アカウントはベストプラクティスに従う必要がある</li></ul><hr><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>このレッスンを読み終えたら、以下を理解していることを確認してください：</p><ul><li>[ ] このプラグインを使用することはGoogle ToSに違反する可能性があり、リスクは自己責任である</li><li>[ ] 新しいアカウント＋Pro/Ultraサブスクリプションは高リスクシナリオである</li><li>[ ] 既存のGoogleアカウントの使用が推奨される</li><li>[ ] 複数アカウントの設定によりリスクを分散できる</li><li>[ ] アカウントが停止された場合、異議申し立てによる回復は不可能である</li><li>[ ] リクエスト頻度と使用量のコントロールが重要である</li></ul><hr><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><p>このレッスンでは、Antigravity Authプラグインを使用することで直面する可能性のあるリスクを紹介しました：</p><ol><li><strong>コアリスク</strong>：Google ToSに違反する可能性があり、アカウントが停止またはシャドウバンされる可能性がある</li><li><strong>高リスクシナリオ</strong>：新しいアカウント、新しいアカウント＋サブスクリプション、密集したリクエスト、単一の重要なアカウント</li><li><strong>ベストプラクティス</strong>：古いアカウントを使用する、複数アカウントを設定する、使用量をコントロールする、状態をモニタリングする、先に「ウォームアップ」する</li><li><strong>よくある質問</strong>：異議申し立て不可、リスクは個人による、複数アカウントで影響を軽減可能</li></ol><p>このプラグインを使用する前に、リスクを慎重に評価してください。アカウントが停止される可能性がある結果を受け入れることができない場合は、<a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a> を直接使用することをお勧めします。</p><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><p>このレッスンの内容は、プロジェクトのREADMEドキュメントのリスク警告セクション（README.md:23-40）に基づいており、具体的なコード実装は含まれていません。</p><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>ToS警告声明</td><td><a href="https://github.com/NoeFabris/opencode-antigravity-auth/blob/main/README.md#L23-L40" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>23-40</td></tr></tbody></table></details>',99)])])}const c=t(e,[["render",r]]);export{u as __pageData,c as default};
